// Biome data: gallowdark. Self-contained, private use.
// Registers into window-level MAPS/OBJECTS/OBJECTS_DATA/TERRAIN_GLOSSARY/TERRAIN_TERMS/BIOME_RULES.
(function(){
  if(typeof MAPS==='undefined'){MAPS={};} if(typeof OBJECTS==='undefined'){OBJECTS={};} if(typeof OBJECTS_DATA==='undefined'){OBJECTS_DATA={};}
  if(typeof TERRAIN_GLOSSARY==='undefined'){TERRAIN_GLOSSARY={};} if(typeof TERRAIN_TERMS==='undefined'){TERRAIN_TERMS={};} if(typeof BIOME_RULES==='undefined'){BIOME_RULES={};}
  MAPS["gallowdark"] = {
    "m1": "data:image/png;base64,",
    "m2": "data:image/png;base64,",
    "m3": "data:image/png;base64,",
    "m4": "data:image/png;base64,",
    "m5": "data:image/png;base64,",
    "m6": "data:image/png;base64,",
  };
  OBJECTS["gallowdark"] = {
    "A1": "data:image/png;base64,",
    "A2": "data:image/png;base64,",
    "A3": "data:image/png;base64,",
    "A4": "data:image/png;base64,",
    "B1": "data:image/png;base64,",
    "B2": "data:image/png;base64,",
    "B3": "data:image/png;base64,",
  };
  OBJECTS_DATA["gallowdark"] = {
    "A1": {name:"Long Wall", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Heavy and Wall terrain.</li></ul>"},
    "A2": {name:"Long Wall w/ Pillars", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Heavy and Wall terrain.</li></ul>"},
    "A3": {name:"Long Wall w/ Hatchway", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Heavy and Wall terrain.</li><li class=\"desc-green\">Includes a Hatchway (see terrain glossary) — begins the battle closed.</li></ul>"},
    "A4": {name:"Long Wall w/ Hatchway & Pillars", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Heavy and Wall terrain.</li><li class=\"desc-green\">Includes a Hatchway (see terrain glossary) — begins the battle closed.</li></ul>"},
    "B1": {name:"Short Wall", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Heavy and Wall terrain.</li></ul>"},
    "B2": {name:"Short Wall w/ Hatchway", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Heavy and Wall terrain.</li><li class=\"desc-green\">Includes a Hatchway (see terrain glossary) — begins the battle closed.</li></ul>"},
    "B3": {name:"Short Wall w/ Hatchway & Pillars", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Heavy and Wall terrain.</li><li class=\"desc-green\">Includes a Hatchway (see terrain glossary) — begins the battle closed.</li></ul>"},
  };
  TERRAIN_GLOSSARY["gallowdark"] = {
    "Wall": "<p>Wall terrain (Gallowdark-specific — these rules apply on top of Heavy).</p><ul class=\"gloss-list\"><li>Operatives cannot move over or through Wall terrain.</li><li>Visibility cannot be determined over or through Wall terrain.</li><li>Other than to areas of the killzone (centre, drop zones, etc.), distances cannot be measured over or through Wall terrain — measure around it by the shortest route.</li><li>For Cover and Obscured, only the corners and ends of Wall terrain can intervene, unless the active operative has passed it.</li></ul>",
    "Hatchway": "<p>A hatchway has two statuses: closed and open. It has two parts — an access point and a hatch — whose terrain types depend on status. Use Operate Hatch to change it. Hatchways begin the battle closed.</p><p><b>Closed</b></p><ul class=\"gloss-list\"><li>The hatch must be fully shut.</li><li>The access point and hatch are Heavy and Wall terrain.</li></ul><p><b>Open</b></p><ul class=\"gloss-list\"><li>The hatch must be fully open (not ajar).</li><li>The access point is Accessible, Insignificant and Exposed terrain.</li><li>The hatch is Heavy and Wall terrain, and the gap directly underneath it is Blocking terrain.</li><li>As the access point is Exposed, the walls either side of it must be used for cover and obscuring instead of the access point.</li></ul>",
    "Heavy": "<p>It can obscure operatives.</p><p>Obscured — An operative is obscured if there's intervening Heavy terrain. However, it cannot be obscured by intervening Heavy terrain within 1\" of either operative.</p><p>When shooting, if the target is obscured:</p><ul class=\"gloss-list\"><li>The attacker must discard one success of their choice instead of retaining it.</li><li>All the attacker's critical successes are retained as normal successes and cannot be changed to critical successes (this takes precedence over all other rules).</li></ul>",
    "Accessible": "<p>Operatives can move through Accessible terrain (this takes precedence over Bases, and Terrain and Movement), but it counts as an additional 1\" to do so.</p>",
    "Blocking": "<p>Blocking terrain is usually the gaps between or underneath a terrain feature. Visibility cannot be drawn through such gaps, and for the purposes of Cover and Obscured, the gaps are intervening like the terrain around them.</p>",
    "Exposed": "<p>For the purposes of Cover and Obscured, it's never intervening.</p>",
    "Insignificant": "<p>For the purposes of climbing and dropping, ignore it.</p>",
    "Cover": "<p>An operative is in cover if there's intervening terrain within its control range. However, it cannot be in cover while within 2\" of the other operative.</p><ul class=\"gloss-list\"><li>If the target operative is in cover, they can retain one normal success without rolling it.</li></ul>",
    "Obscured": "<p>An operative is obscured if there's intervening Heavy terrain. However, it cannot be obscured by intervening Heavy terrain within 1\" of either operative.</p><p>When shooting, if the target is obscured:</p><ul class=\"gloss-list\"><li>The attacker must discard one success of their choice instead of retaining it.</li><li>All the attacker's critical successes are retained as normal successes and cannot be changed to critical successes.</li></ul>",
  };
  TERRAIN_TERMS["gallowdark"] = ["Insignificant","Accessible","Hatchway","Blocking","Obscured","Exposed","Heavy","Cover","Wall"];
  BIOME_RULES["gallowdark"] = {
    name:"Gallowdark",
    rules:[
      {name:"Condensed Environment", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Weapons with the Blast, Torrent and/or x\" Devastating (i.e. Devastating with a distance requirement) weapon rule also have the Lethal 5+ weapon rule.</li></ul>"},
    ],
    actions:[
      {name:"Guard", ap:"1AP", desc:"The operative goes on guard until any of the following are true:<ul class=\"desc-list\"><li class=\"desc-green\">It performs any action, moves or is set up.</li><li class=\"desc-green\">An enemy operative ends an action within its control range and you don't interrupt that activation (see On Guard).</li><li class=\"desc-green\">Its order is changed.</li><li class=\"desc-green\">It's the start of the next turning point.</li></ul>", restrict:"This action is treated as a Shoot action. An operative cannot perform this action while it has a Conceal order, or while it's within control range of an enemy operative.", sub:{name:"On Guard", desc:"<p>Once during each enemy operative's activation, after it performs an action, you can interrupt that activation and select one friendly operative on guard to perform the Fight or Shoot action for free (including actions treated as such, e.g. Hatchway Fight). That operative then cannot counteract during the turning point.</p><p>Determine the target as normal — you don't have to target the operative you interrupted.</p><p>That operative can even Shoot while within control range of an enemy (point-blank shot):</p><ul class=\"desc-list\"><li class=\"desc-green\">Target the enemy operative within control range (even if it wouldn't normally be a valid target).</li><li class=\"desc-green\">Worsen the Hit stat of the weapon by 1.</li><li class=\"desc-green\">Until the end of the interrupted activation, your operative cannot retaliate.</li></ul>"}},
      {name:"Hatchway Fight", ap:"1AP", desc:"Fight with the active operative (see fight sequence). In the Select Enemy Operative step, instead select an enemy operative within 2\" of, and on the other side of, an open hatchway's access point the active operative is touching. For the duration of that action, those operatives are treated as being within each other's control range.", restrict:"This action is treated as a Fight action. An operative cannot perform it while within control range of an enemy operative, or if its base isn't touching an open hatchway's access point."},
      {name:"Operate Hatch", ap:"1AP", desc:"Open or close a hatchway whose access point is within the operative's control range. An operative can perform this during a Dash or Reposition action, and any remaining move distance can be used afterwards.", restrict:"An operative cannot perform this action while within control range of an enemy operative, or if that hatchway is open and its access point is within an enemy operative's control range."},
    ],
  };
})();
